import { Prop, Schema, SchemaFactory } from '@nestjs/mongoose';
@Schema()
export class Equipment {
  @Prop({ unique: true, required: true })
  serialNumber: string;
  @Prop()
  status: string;
}
export const EquipmentSchema = SchemaFactory.createForClass(Equipment);

import { Injectable, BadRequestException, InternalServerErrorException } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Equipment } from './schemas/equipment.schema';
@Injectable()
export class EquipmentsService {
  constructor(@InjectModel(Equipment.name) private model: Model<Equipment>) {}
  async create(dto: any) {
    try {
      return await this.model.create(dto);
    } catch(e: any) {
      if (e.code === 11000) throw new BadRequestException('Duplicado');
      throw new InternalServerErrorException();
    }
  }
  async findAll() { return this.model.find(); }
  async findOne(id: string) { return this.model.findById(id); }
  async update(id: string, dto: any) { return this.model.updateOne({ _id: id }, dto); }
  async remove(id: string) { return this.model.deleteOne({ _id: id }); }
  async removeDefective() { return this.model.deleteMany({ status: 'defectuoso' }); }
}

import { Controller, Post, Get, Put, Delete, Param, Body, HttpCode, HttpStatus } from '@nestjs/common';
import { EquipmentsService } from './equipments.service';
import { MongoIdPipe } from '../common/pipes/mongo-id.pipe';
@Controller('equipments')
export class EquipmentsController {
  constructor(private readonly service: EquipmentsService) {}
  @Post()
  @HttpCode(HttpStatus.CREATED)
  create(@Body() dto: any) { return this.service.create(dto); }
  @Get()
  findAll() { return this.service.findAll(); }
  @Get(':id')
  findOne(@Param('id', MongoIdPipe) id: string) { return this.service.findOne(id); }
  @Put(':id')
  update(@Param('id', MongoIdPipe) id: string, @Body() dto: any) { return this.service.update(id, dto); }
  @Delete('defective')
  @HttpCode(HttpStatus.NO_CONTENT)
  removeDefective() { return this.service.removeDefective(); }
  @Delete(':id')
  remove(@Param('id', MongoIdPipe) id: string) { return this.service.remove(id); }
}

import { PipeTransform, Injectable, BadRequestException } from '@nestjs/common';
import { isValidObjectId } from 'mongoose';
@Injectable()
export class MongoIdPipe implements PipeTransform {
  transform(value: any) {
    if(!isValidObjectId(value)) throw new BadRequestException();
    return value;
  }
}

